$$, $$f739e7040b5af1b832e7724e4e97ad2b8707157769462971ada98ea000963efa$$, $${"A": "16bcce0126ef47b70fe044a956bb2a9b66921bf7e5070084b4c96e8e6ea7756b", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "97e3b018501e349555fd81442d19d0b298dc171134b95adb6f3c60165301bf59"}$$::jsonb, $$Budget J-Books/FY26/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$, 306, $$2026-05-10T04:01:21.372876+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605450A$$, 2026, $$The AGM-179 Joint Air-to-Ground Missile (JAGM) program is an Army-led, Acquisition Category (ACAT) 1C Major Defense Acquisition Program (MDAP) with joint
interest with the Navy, Marine Corps, and Air Force. JAGM is the next generation, multi-mode, air-to-ground munition replacing legacy HELLFIRE (HF) and HF Longbow
munitions. JAGM will be used for destruction of high-value land and maritime targets, moving or stationary, and is capable of being fired from any platform currently
firing HF from a US Army-issued M299 launcher. JAGM utilizes a HF back-end (propulsion, warhead and control system) with a new-design, Millimeter Wave (MMW)
and Semi-Active Laser (SAL), multi-mode guidance section. The multi-mode capability provides fire-and-forget and precision-point targeting as well as unique, blended
modes of each, for improved capability over legacy munitions.$$, $$The AGM-179 Joint Air-to-Ground Missile (JAGM) program is an Army-led, Acquisition Category (ACAT) IC Major Defense Acquisition Program (MDAP) with joint
interest with the United States (U.S.) Air Force, U.S. Marine Corps (USMC), and U.S. Navy. The JAGM is the next generation of aviation-launched, fire and forget
missiles to replace the HELLFIRE Laser and Longbow radar missiles. JAGM will be used by joint service aircraft for destruction of high value stationary, moving, and
relocatable land and maritime targets from standoff range in day, night, adverse weather, and obscured battlefield conditions.

B. Accomplishments/Planned Programs ($ in Millions)                                                                                    FY 2024          FY 2025     FY 2026
Title: Integration and Counter Measure/Threat Management                                                                                   2.904            2.919          -
Description: The Air-to-Ground Missile Systems (AGMS) Product Office and Other Government Agencies (OGAs) will continue
objective platform review, analysis, and threat management. The AGMS Product Office and OGAs will perform technical
assessments, concept studies, prepare documentation, and perform demonstrations and risk reduction efforts.

FY 2025 Plans:
The AGMS Product Office will continue to address design and development of Congressional mandates to include extended
range motor and third sensor. AGMS teams will support development of technical documentation to include master test plans,
specifications, diagrams, drawings, test reports, and requirements documentation. AGMS will also support long lead test
procurement, risk reduction assessments, and all required design verification testing.
FY 2025 to FY 2026 Increase/Decrease Statement:
Effort will fully transition to MSLS Procurement, C70302 / Joint Air-to Ground MSLS to support JAGM fielding.
Title: SBIR/STTR Transfer                                                                                                                       -           0.111             -
