INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605606A$$, 2026, $$The Airworthiness Certification Program Element (PE) assures safe flight operation of Army aircraft and aviation systems by means of technical design approval
and qualification of systems to appropriate airworthiness standards. This PE supports independent airworthiness qualification for all assigned developmental and
in-production Army aircraft, both manned and unmanned, as required by Army Regulation (AR) 70-62, "Airworthiness of Aircraft Systems", and is essential for
assuring the safe operation of Army aircraft. This PE performs engineering functions (design, analysis, testing, demonstrations, and system specification compliance)
essential for certifying the airworthiness of nearly 20,000 assigned Army aircraft. This PE also supports: management/execution of the Army Military Airworthiness
Certification Criteria (AMACC) program; management/execution of airworthiness approval for new systems and materiel changes for all assigned Army aircraft systems;
airworthiness engineering support for major development/modification and future systems/subsystems requirements of the Program Executive Officer for Aviation (PEO
AVN) and U.S. Army Special Operations Command's Technology Applications Program Office (TAPO); and management of test and evaluation processes in support
of the airworthiness qualification process. The Airworthiness Certification PE also performs general research and development in support of aircraft qualification and
overarching airworthiness projects that involve multiple aircraft models, and supports the application of other critical aviation subsystems onto Army aircraft.

 This PE also supports: airworthiness certification for military-use civil derivative aircraft technical qualification through the Federal Aviation Administration's Military
 Certification Office; development of airworthiness procedures, specifications, critical standards, and other design and qualification documents; participation in senior
 leadership mandated airworthiness tri-service activities (e.g., National Airworthiness Council) and international airworthiness related activities mandated by treaty (e.g.,
 Flight Into Non-segregated Airspace (FINAS)). The Aircraft Certification line is the only legal means per fiscal law to proactively establish certification criteria for priority
 research areas per the Army Modernization Strategy being leveraged in Army Aviation programs of record. This includes airworthiness involvement in Technology
 Transition projects such as the Future Long Range Assault Aircraft, Advanced Unmanned Aircraft Systems, Modular Open System Architecture, Autonomy/Artificial
 Intelligence/Machine Learning, Digital Engineering, Electric and Hybrid Propulsion and additive manufacturing.

 Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM), Aviation &
 Missile Center (AvMC), Redstone Arsenal, AL.

 The FY 2026 request was reduced by $0.143 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in
 alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."

 The FY 2026 request was reduced by $0.012 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the
 President's Department of Government Efficiency Workforce Optimization Initiative."
